INSERT INTO public.questions VALUES ('a3cbe0c2-1caa-40f6-b930-3a4bd267518a', '68c8d11b-2a01-4c97-adb6-3bc0f470a4bb', 'matching', 'Questions 14–19', '', '<p>Write the correct number, <strong data-path-to-node="6" data-index-in-node="148">i–vii</strong>, in boxes 14–19 on your answer sheet.</p>', 'matching_paragraph_information', 'null', 'null', '{"layoutType": "heading", "summaryText": "", "answerOptions": [{"optionText": "i The behaviour of a small animal expanding its territory"}, {"optionText": "ii The urban environment encouraging the spread of imported flora and fauna"}, {"optionText": "iii Insects that thrive in urban areas"}, {"optionText": "iv A creature which likes rubbish"}, {"optionText": "v Creatures which change their shape and colour"}, {"optionText": "vi Why natural scientists are interested in studying urban areas"}, {"optionText": "vii Changes in the urban built environments encourage particular species"}], "matchingItems": []}', 'null', '[{"content": "<p><strong data-path-to-node=\"4\" data-index-in-node=\"0\">14. Paragraph A — {vi. Why natural scientists are interested in studying urban areas}</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"11\">“…a growing number [of ecologists] have <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"53\">turned their attention</strong> to the complex interactions of the wildlife that inhabits <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"134\">concrete jungles</strong>… research is <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"166\">timely</strong>… we need to understand how cities are changing the ecology…”</em></li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn A giải thích lý do tại sao các nhà sinh thái học (natural scientists) lại chuyển hướng sang nghiên cứu đô thị (urban areas/concrete jungles). Đó là vì dân số thế giới đang tập trung về thành phố và nghiên cứu này mang tính cấp thiết (timely).</li>\n</ul>\n<p><strong data-path-to-node=\"6\" data-index-in-node=\"0\">15. Paragraph B — {iv. A creature which likes rubbish}</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"11\">“…it is known as the <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"34\">‘garbage turkey’</strong>. The bird’s reputation for digging through inner-city <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"105\">bins</strong> and scavenging street <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"132\">garbage</strong>…”</em></li>\n<li><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “A creature” ở đây chính là chim <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"45\">white ibis</strong>. Đặc điểm nổi bật nhất được nhắc đến là thói quen bới rác (garbage/bins) để tìm thức ăn, đúng với tiêu đề “sinh vật thích rác”.</li>\n</ul>\n<p><strong data-path-to-node=\"8\" data-index-in-node=\"0\">16. Paragraph C — {vii. Changes in the urban built environments encourage particular species}</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"11\">“…homeowners prefer to landscape their backyards with <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"67\">tall trees and manicured lawns</strong>… Gardens filled with flowering plants and fruit trees <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"154\">favour omnivorous birds</strong> such as currawongs…”</em></li>\n<li><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn C mô tả việc thay đổi cách làm vườn của con người (từ bụi rậm sang cây cao và cỏ) đã tạo điều kiện thuận lợi (favour/encourage) cho một số loài chim cụ thể (particular species) như noisy miner, đồng thời làm suy giảm các loài chim nhỏ.</li>\n</ul>\n<p><strong data-path-to-node=\"10\" data-index-in-node=\"0\">17. Paragraph D — {iii. Insects that thrive in urban areas}</strong></p>\n<ul data-path-to-node=\"11\">\n<li><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"11\">“Many <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"17\">invertebrates</strong>, such as the golden orb-weaver <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"62\">spider</strong> and the blue triangle <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"91\">butterfly</strong>, also relish living in the city… Hochuli has also found some varieties of <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"177\">ant</strong>…”</em></li>\n<li><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Insects” (côn trùng) ở đây đại diện cho nhóm động vật không xương sống (invertebrates) như nhện, bướm và kiến. Đoạn này tập trung giải thích lý do tại sao chúng lại phát triển mạnh (thrive/relish living) ở thành phố (như nhiệt độ ấm hơn).</li>\n</ul>\n<p><strong data-path-to-node=\"12\" data-index-in-node=\"0\">18. Paragraph E — {i. The behaviour of a small animal expanding its territory}</strong></p>\n<ul data-path-to-node=\"13\">\n<li><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"11\">“…the rabbit-sized, long-nosed <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"44\">bandicoot</strong> has discovered the advantages of <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"87\">venturing out to grassy suburban backyards</strong>… Dr Price is trying to understand what encourages the little mammal into urban environments.”</em></li>\n<li><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Small animal” chính là loài chuột túi bandicoot. Đoạn văn mô tả hành vi của chúng khi mạo hiểm rời khỏi các khu bụi rậm để tiến vào (expanding its territory) các khu vườn ở ngoại ô để kiếm ăn.</li>\n</ul>\n<p><strong data-path-to-node=\"14\" data-index-in-node=\"0\">19. Paragraph F — {ii. The urban environment encouraging the spread of imported flora and fauna}</strong></p>\n<ul data-path-to-node=\"15\">\n<li><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"15,0,0\" data-index-in-node=\"11\">“It’s not just native wildlife… <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"45\">Non-native species</strong> such as black rodents, cockroaches and foxes… But <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"116\">weeds</strong> are the pest that has gained the most advantage.”</em></li>\n<li><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Imported flora and fauna” (động thực vật nhập khẩu) tương ứng với “Non-native species” (loài không bản địa) và “introduced plant life/weeds” (cỏ dại ngoại lai). Đoạn văn giải thích cách môi trường đô thị (hệ thống nước thải, bê tông) giúp những loài này xâm nhập và lấn át loài bản địa.</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('d25acf4f-2045-4746-93aa-3af24ebb29c5', '9e0aeac0-4f2d-4f75-ad32-ff877189d86f', 'radio', 'Questions 1–7', '', '<p data-start="18" data-end="220">Choose <strong data-start="25" data-end="33">TRUE</strong> if the statement agrees with the information given in the text, choose <strong data-start="105" data-end="114">FALSE</strong> if the statement contradicts the information, or choose <strong data-start="171" data-end="184">NOT GIVEN</strong> if there is no information on this.</p>', 'true_false_not_given', '[{"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The cranberry requires a specific soil type to enable it to grow successfully"}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "A layer of clay protects kettle ponds from harmful substances which could affect the water quality"}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "In the past, the Wampanoag people had to consume most cranberries shortly after picking them"}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The Wampanoag people took advantage of the medicinal properties of cranberries"}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The first settlers in North America brought European varieties of cranberry with them when they arrived"}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Captain Hall tried growing other fruit crops before cultivating cranberries"}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "It took a long time for Captain Hall’s methods of cultivation to become popular among other cranberry producers"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">1. TRUE — The cranberry requires a specific soil type to enable it to grow successfully.</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"5,0,0\" data-index-in-node=\"26\">“These small, crimson berries thrive only in very unique environmental conditions, particularly in soil that is both sandy and acidic.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi nói quả nam việt quất đòi hỏi một loại đất cụ thể (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"71\">a specific soil type</em>) để có thể phát triển thành công. Bài đọc xác nhận loài quả này chỉ phát triển mạnh (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"177\">thrive only</em>) trong điều kiện môi trường rất độc đáo, cụ thể là đất phải vừa có cát vừa có tính axit (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"278\">sandy and acidic</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">2. TRUE — A layer of clay protects kettle ponds from harmful substances which could affect the water quality.</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"7,0,0\" data-index-in-node=\"26\">“The clay bottom acts as a protective barrier, preventing harmful substances from entering the pond and preserving the clean water essential for healthy vines.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi nói một lớp đất sét bảo vệ các ao kettle khỏi các chất độc hại gây ảnh hưởng chất lượng nước. Bài đọc khẳng định phần đáy bằng đất sét đóng vai trò như một rào cản bảo vệ (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"192\">protective barrier</em>), ngăn chặn các chất có hại (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"240\">harmful substances</em>) xâm nhập vào ao để bảo vệ nguồn nước sạch.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">3. FALSE — In the past, the Wampanoag people had to consume most cranberries shortly after picking them.</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"9,0,0\" data-index-in-node=\"26\">“The fruit''s sharp taste lent itself to preservation techniques; communities developed methods of drying and combining cranberries with other foods to extend their usefulness during months when fresh plants were scarce.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi nói trong quá khứ người Wampanoag phải tiêu thụ hầu hết quả nam việt quất ngay sau khi hái (<em data-path-to-node=\"9,1,0\" data-index-in-node=\"112\">shortly after picking them</em>). Ngược lại, bài đọc chỉ ra họ đã phát triển các kỹ thuật bảo quản (<em data-path-to-node=\"9,1,0\" data-index-in-node=\"207\">preservation techniques</em>), sấy khô (<em data-path-to-node=\"9,1,0\" data-index-in-node=\"242\">drying</em>) để kéo dài thời gian sử dụng (<em data-path-to-node=\"9,1,0\" data-index-in-node=\"280\">extend their usefulness</em>) vào những tháng khan hiếm. Thông tin mâu thuẫn trực tiếp nên chọn <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"371\">FALSE</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">4. TRUE — The Wampanoag people took advantage of the medicinal properties of cranberries.</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"11,0,0\" data-index-in-node=\"26\">“In addition to dietary uses, the Wampanoag also employed the berry in first-aid traditions: crushed fruit was applied to sores and minor wounds, reflecting a practical knowledge of its cleansing properties.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi nói người Wampanoag đã tận dụng các đặc tính chữa bệnh/dược tính (<em data-path-to-node=\"11,1,0\" data-index-in-node=\"86\">medicinal properties</em>) của quả nam việt quất. Bài đọc viết họ áp dụng loại quả này vào truyền thống sơ cứu (<em data-path-to-node=\"11,1,0\" data-index-in-node=\"193\">first-aid traditions</em>), đắp quả giã nát lên các vết loét và vết thương nhỏ (<em data-path-to-node=\"11,1,0\" data-index-in-node=\"268\">applied to sores and minor wounds</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">5. FALSE — The first settlers in North America brought European varieties of cranberry with them when they arrived.</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"13,0,0\" data-index-in-node=\"26\">“Rather than attempting to transplant European varieties, the newcomers adopted the native species already adapted to regional conditions.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi khẳng định những người định cư đầu tiên mang theo các giống việt quất châu Âu (<em data-path-to-node=\"13,1,0\" data-index-in-node=\"99\">brought European varieties</em>) khi họ đến. Ngược lại, bài đọc viết rằng thay vì cố gắng cấy ghép các giống châu Âu, những người mới đến đã tiếp nhận và dùng luôn các loài bản địa (<em data-path-to-node=\"13,1,0\" data-index-in-node=\"276\">adopted the native species</em>) sẵn có. Thông tin bị trái ngược hoàn toàn nên chọn <strong data-path-to-node=\"13,1,0\" data-index-in-node=\"355\">FALSE</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">6. NOT GIVEN — Captain Hall tried growing other fruit crops before cultivating cranberries.</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"15,0,0\" data-index-in-node=\"26\">“One Massachusetts grower, Captain Henry Hall, observed that windblown sand reaching his beds improved fruit quality and yield.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ giới thiệu Captain Henry Hall là một người trồng trọt ở Massachusetts và ông đã tình cờ phát hiện ra việc rải cát giúp cải thiện chất lượng quả việt quất. Bài viết <strong data-path-to-node=\"15,1,0\" data-index-in-node=\"188\">hoàn toàn không có thông tin</strong> nào nói về việc trước đó ông ấy có từng thử trồng các loại cây ăn quả khác (<em data-path-to-node=\"15,1,0\" data-index-in-node=\"293\">tried growing other fruit crops</em>) hay chưa.</p>\n</li>\n</ul>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">7. NOT GIVEN — It took a long time for Captain Hall’s methods of cultivation to become popular among other cranberry producers.</strong></p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"17,0,0\" data-index-in-node=\"26\">“He began deliberately applying sand to his plots and found that the practice changed both soil texture and pest incidence for the better.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc có nói hành động rải cát của Hall là một bước tiến quan trọng hướng tới việc canh tác nam việt quất có hệ thống, nhưng <strong data-path-to-node=\"17,1,0\" data-index-in-node=\"139\">không hề đề cập</strong> đến việc mất bao lâu để phương pháp của ông trở nên phổ biến (<em data-path-to-node=\"17,1,0\" data-index-in-node=\"217\">become popular</em>) đối với các nhà sản xuất khác.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('da83d329-2dc2-42e7-a356-cf65ba02dbff', '20107996-5343-4603-aea1-32b10c1fc313', 'fillup', 'Questions 31–40', '<div class="quests-inner-desc">
<div class="txt">
<p>Complete the notes below.</p>
<p>Write <strong>ONE WORD ONLY </strong>for each answer.</p>
</div>
</div>
<div class="quests-des">
<div class="content-write">
<p class="ql-align-center"><strong>BOAR AND RED DEER</strong></p>
<p><strong>Boar</strong></p>
<p>– Boar is not a <span class="fill-history-correct">{protected}</span> species.</p>
<p>– Their number should be controlled as a result of their damage to the {environment}.</p>
<p>– They also spread <span class="fill-history-correct">{diseases}</span>.</p>
<p>– Law was passed regarding banning use of {poison} in killing boars.</p>
<p>– Measures should be taken to keep the boars in the {forest} away from people in urban areas.</p>
<p>– The early 1990s witnessed a significant population rise of boars due to their escape from <span class="fill-history-correct">{farms}</span>.</p>
<p><strong>Red Deer</strong></p>
<p>– Red deer can also damage agricultural produce, such as grain and <span class="fill-history-correct">{potatoes}</span>.</p>
<p>– In winter the red deer come out to the villages for <span class="fill-history-correct">{food}</span>.</p>
<p>– The number of deer keep stable for <span class="fill-history-correct">{hunting}</span>.</p>
<p>– Deer can have a devastating effect on the local <span class="fill-history-correct">{crops}</span>.</p>
</div>
</div>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">PART 4: CONTROL OF WILD ANIMALS (BOAR AND RED DEER)</strong></p>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Jim Robinson:</strong> Good morning. My name’s Jim Robinson and today we’re going to look at the control of wild animals, specifically wild boar.</p>\n<p id=\"p-rc_56e5fcb74799d450-33\" data-path-to-node=\"4\">Now, boar have been natural inhabitants of Western Europe for thousands of years, but in recent years there has been a surge in boar activity that poses a real threat. Boars are not currently on the <strong data-path-to-node=\"4\" data-index-in-node=\"199\">(31) <span class=\"citation-954 citation-955\">protected</span></strong><span class=\"citation-954 citation-955 citation-end-955\"> animals list, which is perhaps why there has been a spike in their breeding activity.</span></p>\n<p id=\"p-rc_56e5fcb74799d450-34\" data-path-to-node=\"5\"><span class=\"citation-952 citation-953 citation-end-953\">Boars are an indigenous species and are particularly plentiful in rural France and the Bavarian uplands of Germany. Boar hunting is a European tradition that goe</span><span class=\"citation-952 citation-end-952\">s back to Roman times and became particularly popular among courtiers during the Middle Ages. Even during the 20th century, boar hunting was seen as an integral part of</span> rural life.</p>\n<p id=\"p-rc_56e5fcb74799d450-35\" data-path-to-node=\"6\">The decline in boar hunting has obviously led to a rise in the boar populations of Europe, and the situation has reached a critical point with boar posing a critical threat to the <strong data-path-to-node=\"6\" data-index-in-node=\"180\">(32) <span class=\"citation-951\">environment</span></strong><span class=\"citation-951 citation-end-951\">. Proponents of boar hunting cite this factor as a major reason why boar populations should be contained. Boar also pose a threat to humans too, with countless reports of people being injured dur</span>ing boar attacks.</p>\n<p id=\"p-rc_56e5fcb74799d450-36\" data-path-to-node=\"7\">The origins of the wild boar have roots in Germanic, and this perhaps explains their prevalence in Germany. The problems with the boar population in Germany have ramifications for the rest of Europe as boar packs migrate towards central and Eastern Europe. One of the main issues that is of great concern is the transmission of <strong data-path-to-node=\"7\" data-index-in-node=\"328\">(33) <span class=\"citation-949 citation-950\">diseases</span></strong><span class=\"citation-949 citation-950 citation-end-950\"> that infect other species. Dairy farmers in France are particularly concerned as many of them have seen their herds depleted by infections.</span></p>\n<p id=\"p-rc_56e5fcb74799d450-37\" data-path-to-node=\"8\"><span class=\"citation-947 citation-948 citation-end-948\">The methods for containing boar populations have been looked at in great detail and numerous options are avai</span><span class=\"citation-947 citation-end-947\">lable. One is to encourage more boar hunting in wild regions such as mountains and forests. Hunters would be given lic</span>ences to hunt either for food or sport. Of course, boar do pose a threat to human life, so this possibility must be looked at with caution.</p>\n<p id=\"p-rc_56e5fcb74799d450-38\" data-path-to-node=\"9\">One method that must be ruled out is <strong data-path-to-node=\"9\" data-index-in-node=\"37\">(34) <span class=\"citation-945 citation-946\">poison</span></strong><span class=\"citation-945 citation-946 citation-end-946\">, as legislation has been introduced prohibiting this. Such methods were tried with rabbits in the 1960s and this had a disastrous impact on the food chain. The introduction of natural predators into the ecosystem is also an option that can’t be considered. The only known predators of boar in the world are wild cat</span><span class=\"citation-945 citation-end-945\">s like lions and tigers. Obviously, there’s no way such animals can be allowed to roam the mountains and forests of Europe.</span></p>\n<p id=\"p-rc_56e5fcb74799d450-39\" data-path-to-node=\"10\"><span class=\"citation-944 citation-end-944\">Given the threat</span> that boars pose to humans, it is imperative that forest-dwelling boar are kept well away from people in cities. This is absolutely essential as human safety must be the main priority of policy makers. In several European countries, boars were becoming increasingly rare by the 11th century. In Great Britain, King Charles attempted to reintroduce boars in the New <strong data-path-to-node=\"10\" data-index-in-node=\"381\">(35) <span class=\"citation-942 citation-943\">forest</span></strong><span class=\"citation-942 citation-943 citation-end-943\"> area of the country, yet the entire population was almost wiped out during the battles of the English Civil War when roaming soldiers hunted them for food.</span></p>\n<p id=\"p-rc_56e5fcb74799d450-40\" data-path-to-node=\"11\"><span class=\"citation-940 citation-941 citation-end-941\">During the 1980s, wild boar rearing was encouraged and boar populations began to ri</span><span class=\"citation-940 citation-end-940\">se again. By the 1990s, there was a huge rise in the number of boar across England due in large part to the species no longer</span> being forced to live in captivity. Many boar have broken free from <strong data-path-to-node=\"11\" data-index-in-node=\"276\">(36) farms</strong> across England and are breeding at a rapid rate.</p>\n<hr data-path-to-node=\"12\">\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">RED DEER</strong></p>\n<p id=\"p-rc_56e5fcb74799d450-41\" data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Jim Robinson:</strong> Aside from their environmental threats, boars also pose a problem for farmers growing crops and vegetables. Other species such as red deer are a threat to farm produce like grain and <strong data-path-to-node=\"14\" data-index-in-node=\"197\">(37) <span class=\"citation-938 citation-939\">potatoes</span></strong><span class=\"citation-938 citation-939 citation-end-939\">, but boars certainly present the most serious risk. The damage done to the farming industry is estimated to cost millions of pounds, and insurance payments as a result of this have spiked in the last decade.</span></p>\n<p id=\"p-rc_56e5fcb74799d450-42\" data-path-to-node=\"15\"><span class=\"citation-936 citation-937 citation-end-937\">Red deer are predominantly confined </span><span class=\"citation-936 citation-end-936\">to forest areas and it is unusual to see them outside their habitats during the summer months. However, as the weather gets colder, they can be seen looking for</span> <strong data-path-to-node=\"15\" data-index-in-node=\"197\">(38) food</strong> around local villages and fields. Red deer have their origins in Asia and are <span class=\"citation-934 citation-935 citation-end-935\">a ruminant species, which means they have a stomach that consists of four compartments, much like cows. They are slaughtered for food and their meat is sold as venison and is increasingly popular among consume</span><span class=\"citation-934 citation-end-934\">rs.</span></p>\n<p id=\"p-rc_56e5fcb74799d450-43\" data-path-to-node=\"16\"><span class=\"citation-933 citation-end-933\">There are nine subspecies of red deer, with three of them on the endangered species list. The deer population doesn’t pose the same threat as the boar populatio</span>n, but it certainly needs to be addressed. Forest areas are their main habitats and they are now breeding at a much higher rate than in previous years.</p>\n<p id=\"p-rc_56e5fcb74799d450-44\" data-path-to-node=\"17\">Of course, deer are an important part of the food chain and are an important part of the <strong data-path-to-node=\"17\" data-index-in-node=\"89\">(39) hunting</strong> traditions of the UK, so it is important that their population is kept stable for this reason. Though the real concern is the problems that deer present for farmers who have seen their <strong data-path-to-node=\"17\" data-index-in-node=\"287\">(40) <span class=\"citation-932\">crops</span></strong><span class=\"citation-932 citation-end-932\"> suffer in devastating ways. Protection needs to be offered, and many farmers report building large perimeter fences around their fields to keep deer out, which cost them a huge amount of money. Government funding is so far inadequate to offer the protection farmers need, but ways are being looked at to provide subsidies through other mean</span>s.</p>"}]', 0);
INSERT INTO public.questions VALUES ('9409a575-c076-44a2-be31-2d836c6a902f', '829740ea-d9fa-40c1-b63c-49ff29002b93', 'radio', ' Questions 27–31', NULL, '<p>Choose <strong>YES </strong>if the statement agrees with the claims of the writer, choose <strong>NO </strong>if the statement contradicts the claims of the writer, or <strong>NOT GIVEN</strong> if it is impossible to say what the writer thinks about this.</p>
', 'multiple_choice_single', '[{"correct": 2, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Young people are easily persuaded by surveys that listening to music is beneficial."}, {"correct": 0, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Different studies share the same conclusions about the desirability of working in silence."}, {"correct": 2, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Some doctors recommend wearing headphones to lower blood pressure."}, {"correct": 1, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Nathaniel Baldwin was a respected government researcher."}, {"correct": 0, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "The effect of the invention of headphones is comparable to the effect of the invention of the writing."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">27. Young people are easily persuaded by surveys that listening to music is beneficial.</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Đáp án:</strong> NOT GIVEN</p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;In survey after survey, people report with confidence that music makes them happier, better at concentrating, and more productive.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong data-path-to-node=\"5,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ nói rằng người trẻ tham gia khảo sát và tự báo cáo rằng âm nhạc có lợi cho họ. Không có thông tin nào nói rằng họ bị &#8220;thuyết phục&#8221; bởi các khảo sát đó.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">28. Different studies share the same conclusions about the desirability of working in silence.</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Đáp án:</strong> YES</p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;Scientists do not share this belief&#8230; ‘As silence has the best overall performance, it would still be advisable that people work in silence,’ another reporter dryly concluded.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong data-path-to-node=\"7,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Các nhà khoa học và các nghiên cứu (nghiên cứu Đài Loan, nghiên cứu về pop song) đều thống nhất rằng làm việc trong im lặng đem lại hiệu quả tốt nhất.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">29. Some doctors recommend wearing headphones to lower blood pressure.</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Đáp án:</strong> NOT GIVEN</p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;&#8230;evidence that music relaxes our muscles&#8230; and may even moderately reduce blood pressure&#8230;&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong data-path-to-node=\"9,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc có nhắc đến bằng chứng cho thấy âm nhạc có thể giúp giảm huyết áp, nhưng <strong data-path-to-node=\"9,2,0\" data-index-in-node=\"93\">không đề cập</strong> đến việc có &#8220;bác sĩ&#8221; nào đưa ra lời khuyên đeo tai nghe để làm việc này hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">30. Nathaniel Baldwin was a respected government researcher.</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Đáp án:</strong> NO</p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;&#8230;an eccentric inventor and repairman named Nathaniel Baldwin&#8230; he had built, in his kitchen, a new kind of headset&#8230;&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong data-path-to-node=\"11,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Nathaniel Baldwin được mô tả là một &#8220;nhà phát minh và thợ sửa chữa lập dị&#8221; làm việc tại bếp nhà mình, không phải là một &#8220;nhà nghiên cứu chính phủ đáng kính&#8221;.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">31. The effect of the invention of headphones is comparable to the effect of the invention of writing.</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Đáp án:</strong> YES</p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;&#8230;headphones have done what writing and literacy did for language – they made music private.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"13,2,0\"><strong data-path-to-node=\"13,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả trực tiếp so sánh tác động của tai nghe đối với âm nhạc cũng giống như tác động của chữ viết đối với ngôn ngữ: cả hai đều biến những thứ mang tính cộng đồng thành riêng tư.</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('5228e1da-8c34-4d5c-a255-b9dd8c70725a', '829740ea-d9fa-40c1-b63c-49ff29002b93', 'radio', 'Questions 32–36', NULL, '<p>Choose the correct answer.</p>
', 'multiple-choice', '[{"correct": 0, "options": [{"content": "The work is mentally demanding."}, {"content": "It provides employment for younger workers."}, {"content": "It is a small part of a country’s economy."}, {"content": "Workers have to live in urban centres."}], "question": "What does the writer suggest about a service economy?"}, {"correct": 2, "options": [{"content": "emphasizing the diversity of musical forms."}, {"content": "expressing his frustration with the limited archaeological evidence uncovered."}, {"content": "lending support to the view that music has been important in human history."}, {"content": "creating a geographical map of the evolution of music."}], "question": "When the writer mentions the historical evidence for early music he is"}, {"correct": 3, "options": [{"content": "It has caused a reduction in the number of people who listen to music."}, {"content": "It has increased people’s participation in music events."}, {"content": "It has reduced the global variation of music styles."}, {"content": "It has changed the traditional role of music in society."}], "question": "What does the writer say about the social effects of listening to music through headphones?"}, {"correct": 1, "options": [{"content": "Americans are unique in their desire for personal independence."}, {"content": "Personal independence is something that can be purchased."}, {"content": "Striving for personal independence is a recent phenomenon."}, {"content": "Personal independence destroys social connections."}], "question": "What does the writer say about personal independence?"}, {"correct": 0, "options": [{"content": "to support the writer’s own view"}, {"content": "to draw attention to an authoritative book about music"}, {"content": "to raise awareness of people’s loss of listening skills"}, {"content": "to illustrate how music brings people closer to each other"}], "question": "Why does the writer quote Jonah Lehrer in the last paragraph?"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">32. What does the writer suggest about a service economy?</strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Đáp án:</strong> The work is mentally demanding.</p>\n</li>\n<li>\n<p data-path-to-node=\"18,1,0\"><strong data-path-to-node=\"18,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;&#8230;moved&#8230; to a service economy, with an emphasis on jobs in offices that require higher levels of concentration, reflection and creativity.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"18,2,0\"><strong data-path-to-node=\"18,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Nền kinh tế dịch vụ tập trung vào các công việc văn phòng đòi hỏi sự tập trung, suy ngẫm và sáng tạo cao (đòi hỏi về trí óc).</p>\n</li>\n</ul>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">33. When the writer mentions the historical evidence for early music he is</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Đáp án:</strong> lending support to the view that music has been important in human history.</p>\n</li>\n<li>\n<p data-path-to-node=\"20,1,0\"><strong data-path-to-node=\"20,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;Music, together with dance, co-evolved biologically and culturally to serve as a technology of social bonding&#8230; evidence&#8230; dates back to Sumeria, 35,000 years ago&#8230;&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"20,2,0\"><strong data-path-to-node=\"20,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc đưa ra các bằng chứng lịch sử (ký hiệu nhạc Sumeria, sáo xương) nhằm khẳng định âm nhạc đã luôn là một phần quan trọng và lâu đời trong lịch sử nhân loại.</p>\n</li>\n</ul>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">34. What does the writer say about the social effects of listening to music through headphones?</strong></p>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong data-path-to-node=\"22,0,0\" data-index-in-node=\"0\">Đáp án:</strong> It has changed the traditional role of music in society.</p>\n</li>\n<li>\n<p data-path-to-node=\"22,1,0\"><strong data-path-to-node=\"22,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;&#8230;which is a radical departure from music’s social purpose in history&#8230; headphones have&#8230; made music private.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"22,2,0\"><strong data-path-to-node=\"22,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tai nghe đã làm thay đổi vai trò truyền thống của âm nhạc (từ &#8220;chất keo xã hội&#8221; gắn kết mọi người thành một trải nghiệm cá nhân, riêng tư).</p>\n</li>\n</ul>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">35. What does the writer say about personal independence?</strong></p>\n<ul data-path-to-node=\"24\">\n<li>\n<p data-path-to-node=\"24,0,0\"><strong data-path-to-node=\"24,0,0\" data-index-in-node=\"0\">Đáp án:</strong> Personal independence is something that can be purchased.</p>\n</li>\n<li>\n<p data-path-to-node=\"24,1,0\"><strong data-path-to-node=\"24,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;&#8230;wealth can buy – and modern technology can deliver – personal independence&#8230;&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"24,2,0\"><strong data-path-to-node=\"24,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả khẳng định sự giàu có (tiền bạc) có thể mua được sự độc lập cá nhân thông qua công nghệ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">36. Why does the writer quote Jonah Lehrer in the last paragraph?</strong></p>\n<ul data-path-to-node=\"26\">\n<li>\n<p data-path-to-node=\"26,0,0\"><strong data-path-to-node=\"26,0,0\" data-index-in-node=\"0\">Đáp án:</strong> to support the writer’s own view.</p>\n</li>\n<li>\n<p data-path-to-node=\"26,1,0\"><strong data-path-to-node=\"26,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;However, with music&#8230; ‘The answers have been there all along. We just weren’t listening.’ In a crowded world&#8230; a headphone is a small invisible fence around our minds&#8230;&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"26,2,0\"><strong data-path-to-node=\"26,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả trích dẫn Jonah Lehrer để củng cố quan điểm rằng âm nhạc giúp chúng ta hướng sự chú ý vào bên trong để giải quyết vấn đề sáng tạo.</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('c28b132a-38cd-42ef-87f9-316d46a06cae', '829740ea-d9fa-40c1-b63c-49ff29002b93', 'matching', 'Questions 37–40', NULL, '<p>Complete the summary using the list of words, <strong>A-I</strong>, below.</p>
', 'matching_features', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p style=\"text-align: center;\"><strong>HEADPHONES AND CITY LIVING</strong></p>\n<p>Dr Michael Bull believes that listening to music through headphones has changed the {B relationship} the wearers of headphones have with public spaces. Living in the centre of cities is becoming popular, as people become less keen on living in the {E suburbs}. In densely populated city centres, headphones form {G barriers} that isolate people from fellow citizens and from their environment. Wearers of headphones are treated with {A courtesy} that other people do not receive. This is because if we see someone wearing headphones, we believe they must be occupied in some way and should not be interrupted.</p>", "answerOptions": [{"optionText": "A courtesy"}, {"optionText": "B relationship"}, {"optionText": "C difficulty"}, {"optionText": "D countryside"}, {"optionText": "E suburbs"}, {"optionText": "F language"}, {"optionText": "G barriers"}, {"optionText": "H obstacles"}, {"optionText": "I disapproval"}], "matchingItems": null}', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Câu 37</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Đáp án:</strong> B relationship</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;Dr Michael Bull&#8230; has repeatedly made the larger point that personal music devices change how we <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"110\">relate to</strong> public spaces.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Trong bài đọc, cụm từ &#8220;relate to&#8221; (liên quan/tương tác với) được dùng để chỉ mối quan hệ giữa người dùng và không gian công cộng. Do đó, danh từ phù hợp nhất để điền vào chỗ trống là &#8220;relationship&#8221;.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Câu 38</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Đáp án:</strong> E suburbs</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;&#8230;more people are moving from the <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"47\">edges of cities</strong> to live in urban centers.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc đề cập đến việc mọi người di chuyển từ vùng &#8220;edges of cities&#8221; (rìa thành phố) vào trung tâm. Trong danh sách từ cho sẵn, &#8220;suburbs&#8221; (ngoại ô) là từ đồng nghĩa chính xác nhất với vùng rìa thành phố.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Câu 39</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Đáp án:</strong> G barriers</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;Headphones create <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"30\">shields</strong> for wearers, separating them from other people and their surroundings.&#8221; và &#8220;&#8230;a headphone is a small <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"140\">invisible fence</strong> around our minds&#8230;&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong data-path-to-node=\"8,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả sử dụng các hình ảnh so sánh như &#8220;shields&#8221; (tấm khiên) và &#8220;invisible fence&#8221; (hàng rào vô hình) để nói về chức năng của tai nghe. Từ &#8220;barriers&#8221; (rào cản) trong danh sách đáp án phản ánh đúng ý nghĩa của việc tạo ra sự ngăn cách này.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Câu 40</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Đáp án:</strong> A courtesy</p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;Headphones have their own rules of <strong data-path-to-node=\"10,1,0\" data-index-in-node=\"47\">good manners</strong>&#8230; We assume that people wearing them are busy and we should <strong data-path-to-node=\"10,1,0\" data-index-in-node=\"121\">respect their privacy</strong>&#8230;&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"10,2,0\"><strong data-path-to-node=\"10,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Vì người xung quanh coi việc đeo tai nghe là biểu hiện của sự bận rộn và cần được tôn trọng quyền riêng tư (good manners/respect), nên người đeo tai nghe nhận được sự &#8220;courtesy&#8221; (sự lịch sự/nhã nhặn) từ người khác.</p>\n</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('5b5eaee6-164b-40c3-a13b-aebae4fd594a', 'a397dc34-6bf1-43f2-b1ae-251c607e3e6e', 'radio', 'Questions 1–5', '', '<p>Choose <strong>TRUE</strong> if the statement agrees with the information given in the text, choose <strong>FALSE</strong> if the statement contradicts the information, or choose <strong>NOT GIVEN</strong> if there is no information on this.</p>', 'true_false_not_given', '[{"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Artwork from ancient Egypt indicates that the use of candles was limited to royalty."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Tallow was produced exclusively for candle making."}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "In the Middle Ages, candles made from beeswax were more popular than those made from other substances."}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Keeping time at auctions in the 15th century involved marking lines on the surface of a candle."}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The candles used at auctions had to be of good quality."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">1. Artwork from ancient Egypt indicates that the use of candles was limited to royalty. — {FALSE}</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong></p>\n<blockquote data-path-to-node=\"4,0,1\">\n<p data-path-to-node=\"4,0,1,0\"><em data-path-to-node=\"4,0,1,0\" data-index-in-node=\"0\">“Ancient Egyptian artworks depict the use of candles by writers and philosophers who worked long after sundown.”</em></p>\n</blockquote>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong></p>\n<ul data-path-to-node=\"4,1,1\">\n<li>\n<p data-path-to-node=\"4,1,1,0,0\">Câu hỏi khẳng định rằng tác phẩm nghệ thuật từ Ai Cập cổ đại chỉ ra việc sử dụng nến <strong data-path-to-node=\"4,1,1,0,0\" data-index-in-node=\"85\">bị giới hạn chỉ dành cho giới hoàng tộc</strong> (<em data-path-to-node=\"4,1,1,0,0\" data-index-in-node=\"126\">limited to royalty</em>).</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,1,1,0\">Tuy nhiên, bài đọc viết rất rõ ràng: các tác phẩm nghệ thuật Ai Cập cổ đại khắc họa việc nến được sử dụng bởi <strong data-path-to-node=\"4,1,1,1,0\" data-index-in-node=\"110\">các nhà văn và nhà triết học</strong> (<em data-path-to-node=\"4,1,1,1,0\" data-index-in-node=\"140\">writers and philosophers</em>) để làm việc muộn sau khi mặt trời lặn.</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,1,2,0\">Do thông tin về đối tượng sử dụng trong bài đọc mâu thuẫn trực tiếp với từ hạn định tuyệt đối <em data-path-to-node=\"4,1,1,2,0\" data-index-in-node=\"94\">\"limited to royalty\"</em> của câu hỏi, đáp án chính xác bắt buộc phải là <strong data-path-to-node=\"4,1,1,2,0\" data-index-in-node=\"162\">FALSE</strong>.</p>\n</li>\n</ul>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">2. Tallow was produced exclusively for candle making. — {FALSE}</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 1):</strong> <em data-path-to-node=\"10,0,0\" data-index-in-node=\"20\">\"...tallow, the white, nearly tasteless fat of cattle or sheep <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"83\">also used to make soap</strong>.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Từ khóa <strong data-path-to-node=\"10,1,0\" data-index-in-node=\"20\">\"exclusively\"</strong> (duy nhất/độc quyền) làm câu này sai. Bài đọc khẳng định mỡ động vật (tallow) còn được dùng để làm xà phòng (soap).</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">3. In the Middle Ages, candles made from beeswax were more popular than those made from other substances. — {TRUE}</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"12,0,0\" data-index-in-node=\"20\">\"A major improvement... came in the Middle Ages, when <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"74\">beeswax was preferred over animal or vegetable fats</strong>...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Từ \"preferred over\" (được ưa chuộng hơn) đồng nghĩa với \"more popular\". Người thời Trung Cổ chuộng sáp ong hơn mỡ động vật hay thực vật vì nó có mùi dễ chịu và sạch sẽ hơn.</p>\n</li>\n</ul>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">4. Keeping time at auctions in the 15th century involved marking lines on the surface of a candle. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"14,0,0\" data-index-in-node=\"20\">\"At auctions, the bidding time was limited by <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"66\">inserting a pin into a candle</strong> and letting the wax melt until the pin dropped...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cách đo thời gian được mô tả là cắm một chiếc đinh ghim (pin) vào nến. Bài đọc <strong data-path-to-node=\"14,1,0\" data-index-in-node=\"91\">không nhắc gì</strong> đến việc đánh dấu các đường kẻ (marking lines) trên bề mặt nến.</p>\n</li>\n</ul>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">5. The candles used at auctions had to be of good quality. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> Đoạn này chỉ nói về mục đích dùng nến để kết thúc phiên đấu giá khi cái ghim rơi xuống.</p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc <strong data-path-to-node=\"16,1,0\" data-index-in-node=\"20\">không đưa ra thông tin</strong> hay yêu cầu nào về chất lượng (good quality) của những cây nến được sử dụng trong các buổi đấu giá này.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('5ff1af9b-dd95-422e-a36b-7d5db145c040', 'a397dc34-6bf1-43f2-b1ae-251c607e3e6e', 'fillup', 'Questions 6–13', '<p>Complete the notes below.</p>
<p>Write <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<h4 data-path-to-node="4"><strong data-path-to-node="4" data-index-in-node="0">Candle making</strong></h4>
<p data-path-to-node="5"><strong data-path-to-node="5" data-index-in-node="0">Advantages of the various types of wax used in candlemaking</strong></p>
<ul data-path-to-node="6">
<li>
<p data-path-to-node="6,0,0">beeswax made less { mess} than animal fats</p>
</li>
<li>
<p data-path-to-node="6,1,0">spermaceti wax produced a stronger {light}</p>
</li>
<li>
<p data-path-to-node="6,2,0">ozokerite did not melt when the {weather} was hot</p>
</li>
<li>
<p data-path-to-node="6,3,0">paraffin blend made good quality candles which were inexpensive</p>
</li>
</ul>
<p data-path-to-node="7"><strong data-path-to-node="7" data-index-in-node="0">The candlemaking process</strong></p>
<ul data-path-to-node="8">
<li>
<p data-path-to-node="8,0,0">in the dipping method, wicks were made from rushes</p>
</li>
<li>
<p data-path-to-node="8,1,0">in the pouring method, melted beeswax was poured over a wick that was made of {cotton}</p>
</li>
</ul>
<p data-path-to-node="9"><strong data-path-to-node="9" data-index-in-node="0">Candlemaking today</strong></p>
<ul data-path-to-node="10">
<li>
<p data-path-to-node="10,0,0">wax can be obtained from the stem of a {shrub} called candelilla</p>
</li>
<li>
<p data-path-to-node="10,1,0">bayberry wax, used in decorative candles, comes from the plant’s {fruit}</p>
</li>
<li>
<p data-path-to-node="10,2,0">the {casing} of a decorative candle is made from wax which can resist heat</p>
</li>
<li>
<p data-path-to-node="10,3,0">{wire} is often used to keep the wick of a candle upright</p>
</li>
</ul>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">6. mess — {beeswax made less mess than animal fats}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">\"Beeswax was preferred... because it smelled pleasant and <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"78\">did not produce as much mess</strong> as other fats.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm \"did not produce as much\" đồng nghĩa với \"made less\". Sáp ong sạch hơn mỡ động vật vì nó không tạo ra nhiều vết bẩn/sự bừa bộn (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"144\">mess</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">7. light — {spermaceti wax produced a stronger light}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">\"Spermaceti wax was popular because it provided a <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"70\">significantly brighter light</strong>...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Brighter light\" tương ứng với \"stronger light\" (ánh sáng mạnh/sáng hơn).</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">8. weather — {ozokerite did not melt when the weather was hot}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> *\"Ozokerite... was also popular... particularly in <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"71\">warmer weather</strong>, khi điểm nóng chảy cao giúp nó <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"118\">remained firm</strong> [không bị chảy/luôn cứng].\" *</p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Nhờ điểm nóng chảy cao, Ozokerite không bị chảy khi thời tiết (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"75\">weather</strong>) nóng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">9. cotton — {melted beeswax was poured over a wick that was made of cotton}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 5):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">\"In the pouring method... melted beeswax was poured over a suspended <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"89\">cotton wick</strong>...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Trong phương pháp đổ (pouring), bấc nến được làm bằng sợi bông (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"76\">cotton</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">10. shrub — {wax can be obtained from the stem of a shrub called candelilla}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 7):</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"20\">\"...candelilla, which comes from the <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"57\">stem of the candelilla shrub</strong>...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Sáp candelilla được lấy từ thân (stem) của một loại cây bụi (<strong data-path-to-node=\"13,1,0\" data-index-in-node=\"73\">shrub</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">11. fruit — {bayberry wax... comes from the plant’s fruit}</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 8):</strong> <em data-path-to-node=\"15,0,0\" data-index-in-node=\"20\">\"One example is bayberry wax, which is <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"59\">derived from the fruit</strong> of the bayberry bush...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Sáp bayberry được chiết xuất từ quả (<strong data-path-to-node=\"15,1,0\" data-index-in-node=\"49\">fruit</strong>) của cây bayberry.</p>\n</li>\n</ul>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">12. casing — {the casing of a decorative candle is made from wax which can resist heat}</strong></p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 8):</strong> *\"In decorative candles, non-burning wax is used to make the <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"81\">casing</strong>, which is <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"98\">not intended to melt</strong> [resist heat].\" *</p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Phần vỏ ngoài (<strong data-path-to-node=\"17,1,0\" data-index-in-node=\"27\">casing</strong>) của nến trang trí làm từ sáp không cháy để chịu nhiệt, không bị tan chảy khi nến cháy bên trong.</p>\n</li>\n</ul>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">13. wire — {wire is often used to keep the wick of a candle upright}</strong></p>\n<ul data-path-to-node=\"19\">\n<li>\n<p data-path-to-node=\"19,0,0\"><strong data-path-to-node=\"19,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 9):</strong> <em data-path-to-node=\"19,0,0\" data-index-in-node=\"20\">\"Often, these wicks have a <strong data-path-to-node=\"19,0,0\" data-index-in-node=\"47\">center made of wire</strong> that allows them to... <strong data-path-to-node=\"19,0,0\" data-index-in-node=\"90\">remain erect</strong> [upright] in the melted wax.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"19,1,0\"><strong data-path-to-node=\"19,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Sợi dây kim loại (<strong data-path-to-node=\"19,1,0\" data-index-in-node=\"30\">wire</strong>) được đặt ở lõi bấc để giúp nó luôn đứng thẳng (<strong data-path-to-node=\"19,1,0\" data-index-in-node=\"83\">upright/erect</strong>) khi sáp tan chảy.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('6f811950-33ea-4fde-9235-5569758b6fc6', 'd9f36741-3c84-41b4-a1d5-7214b6ae4a2d', 'radio', 'Questions 36-40', '', '<p data-path-to-node="37,0,0">Choose<strong data-path-to-node="37,0,0" data-index-in-node="0"> YES</strong> if the statement agrees with the claims of the writer,<strong data-path-to-node="37,1,0" data-index-in-node="0">NO</strong> if the statement contradicts the claims of the writer,<strong data-path-to-node="37,2,0" data-index-in-node="0">NOT GIVEN</strong> if it is impossible to say what the writer thinks about this</p>', 'yes_no_not_given', '[{"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "A range of different theatrical experiences will be possible at the Curve Theatre."}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "The opening of the Curve Theatre will lead to the closure of other theatres in the region."}, {"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "There are other buildings in the world that can be compared to the Curve Theatre."}, {"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Vinoly''s plans for Battersea have proved popular with the public."}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "The Curve Theatre will suit the style of Paul Kerryson''s productions."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">36. A range of different theatrical experiences will be possible at the Curve Theatre. — {YES}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"11\">“…the theatrical potential of the building is considerable, as the various ‘curtains’ of the stage can be <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"119\">manipulated</strong> and stage areas and seating <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"159\">adjusted</strong>.”</em> (Đoạn 9)</p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Khả năng điều chỉnh linh hoạt khu vực sân khấu, chỗ ngồi và các tấm màn ngăn cách cho phép nhà hát tạo ra nhiều loại hình trải nghiệm sân khấu khác nhau. Tác giả khẳng định tiềm năng này là rất lớn (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"211\">considerable</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">37. The opening of the Curve Theatre will lead to the closure of other theatres in the region. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 3 nhắc đến việc nhà hát Haymarket đã đóng cửa từ năm 2006 (trước khi Curve mở cửa). Đoạn 9 nói Curve sẽ có sức hút lớn trong khu vực (<em data-path-to-node=\"7,0,0\" data-index-in-node=\"150\">regional pre-eminence, and pulling power</em>).</p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Mặc dù Curve có sức mạnh cạnh tranh lớn, nhưng tác giả <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"67\">không hề đưa ra khẳng định hay dự đoán</strong> rằng nó sẽ làm cho các nhà hát khác trong vùng phải <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"158\">đóng cửa</strong> (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"168\">closure</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">38. There are other buildings in the world that can be compared to the Curve Theatre. — {YES}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"11\">“…it <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"18\">repeats aspects</strong> of the sweeping formal bravado of Vinoly’s <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"77\">Tokyo International Forum</strong> and takes its self-dramatizing cue from the <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"147\">Kimmel Center</strong>… in Philadelphia.”</em> (Đoạn 10)</p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả trực tiếp so sánh Curve với hai tòa nhà khác ở Nhật Bản (Tokyo) và Mỹ (Philadelphia). Do đó, việc nói có những tòa nhà khác có thể so sánh được là hoàn toàn chính xác theo ý kiến tác giả.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">39. Vinoly’s plans for Battersea have proved popular with the public. — {NO}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"11\">“…and (<strong data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">if the outraged protests die out</strong>) a vast carbon-neutral scheme next to Battersea power station…”</em> (Đoạn 11)</p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ “outraged protests” (những cuộc biểu tình đầy phẫn nộ) chứng tỏ kế hoạch này đang bị phản đối dữ dội, trái ngược hoàn toàn với việc nó “được công chúng yêu thích” (<em data-path-to-node=\"11,1,0\" data-index-in-node=\"183\">popular with the public</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">40. The Curve Theatre will suit the style of Paul Kerryson’s productions. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"11\">“He’s got what he wanted, a theatre without boundaries: <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"67\">what will he do with it?</strong>“</em> (Câu cuối cùng của bài)</p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả cho biết Paul Kerryson đã có được kiểu nhà hát mà ông ấy muốn (không ranh giới), nhưng tác giả kết thúc bằng một câu hỏi bỏ ngỏ: “Ông ấy sẽ làm gì với nó?”. Tác giả <strong data-path-to-node=\"13,1,0\" data-index-in-node=\"185\">không khẳng định</strong> liệu nhà hát này có thực sự phù hợp (<em data-path-to-node=\"13,1,0\" data-index-in-node=\"239\">suit</em>) với phong cách dàn dựng của Paul hay không, mà chỉ coi đó là một thử thách (<em data-path-to-node=\"13,1,0\" data-index-in-node=\"321\">challenge</em>) dành cho vị đạo diễn này.</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('c49a3109-1a21-41ff-bbb3-92e2cd6978f2', '411fae2d-0b7a-494e-8bc6-5bc1042b89b5', 'radio', 'Questions 5–7', NULL, '<p>Choose the correct answer.</p>
', 'multiple_choice_single', '[{"correct": 0, "options": [{"content": "changing the bed linen"}, {"content": "washing the windows"}, {"content": "cleaning the fridge"}], "question": "Which extra service does the agency agree to provide?"}, {"correct": 1, "options": [{"content": "the children’s room"}, {"content": "the carpet"}, {"content": "the bathroom"}], "question": "What will be cleaned more thoroughly every three months?"}, {"correct": 1, "options": [{"content": "do the washing."}, {"content": "iron the clothes."}, {"content": "put the clothes away."}], "question": "The woman would like the cleaners to"}]', 'null', 'null', 'null', '[{"content": "<p>1</p>\n"}]', 1);
